@extends('admin.layout') @section('title','Return '.$sale->invoice_no) @section('content')<div class="page-head"><div><div class="eyebrow">Refund</div><h1>Return {{ $sale->invoice_no }}</h1><p>Only remaining unreturned quantities can be refunded.</p></div></div><form class="card" method="POST" action="{{ route('admin.sales.return.store',$sale) }}">@csrf<div class="table-wrap"><table><thead><tr><th>Product</th><th>Sold</th><th>Already Returned</th><th>Return Now</th><th>Unit Refund</th></tr></thead><tbody>@foreach($sale->items as $item)<tr><td>{{ $item->product_name }}</td><td>{{ $item->quantity }}</td><td>{{ $item->returned_quantity }}</td><td><input type="number" name="items[{{ $item->id }}]" min="0" max="{{ $item->quantity-$item->returned_quantity }}" step=".001" value="0"></td><td>{{ number_format($item->unit_price,2) }}</td></tr>@endforeach</tbody></table></div><label>Reason</label><input name="reason" required placeholder="Damaged, wrong item, customer request..."><label>Notes</label><textarea name="notes" rows="3"></textarea><button class="btn" style="margin-top:16px">Save Return & Restore Stock</button></form>@endsection
